 16→fn resolve_states(state_filter: &str) -> Vec<&str> {
 17→    match state_filter {
 18→        "all" => vec!["drafts", "pending", "running", "done", "failed", "merged"],
 19→        "active" => vec!["pending", "running", "done"],
 20→        "drafts" => vec!["drafts"],
 21→        other => vec![other],
 22→    }
 23→}
