214→def wait_done [spec_id: string, timeout_min: int = 120] {
215→  let deadline = (date now) + ($timeout_min * 60sec)
216→  loop {
217→    let s = load_state
218→    if $spec_id in $s.completed { return "done" }
219→    if $spec_id in $s.failed    { return "failed" }
220→    if (date now) > $deadline   { return "timeout" }
221→    sleep 15sec
222→  }
223→}
