226→  if $dry_run {
227→    print $"  would spawn: (ansi yellow)zellij pane bop-($spec_id) — ($mode)(ansi reset)"
228→    return {ok: true}
229→  }
230→
231→  let base = $"($PROJECT_DIR)/.auto-claude/specs"
232→  let found = (ls $base | where name =~ $"/($spec_id)-" | get name | first)
233→  let specfile = $"($found)/spec.md"
234→  print $"\n(ansi green_bold)── ($spec_id) ─────────────────────────────────────────(ansi reset)"
235→  print (open $specfile | str substring 0..400)
236→  print "..."
237→
238→  write_approval $spec_id
239→  print $"  (ansi green)✓ approved ($spec_id)(ansi reset)"
240→
241→  let cmd = if $mode == "codex" {
242→    codex_shell_cmd $spec_id
243→  } else {
244→    let flag = if $mode == "direct" { "--direct" } else { "--isolated" }
245→    spec_shell_cmd $spec_id $flag
246→  }
247→  spawn_pane $"bop-($spec_id)" $cmd
248→
249→  print $"  (ansi light_gray)pane bop-($spec_id) running, polling...(ansi reset)"
250→  let outcome = wait_done $spec_id
251→  match $outcome {
252→    "done"    => {ok: true}
253→    "failed"  => {ok: false}
254→    "timeout" => {ok: false}
255→  }
256→}
