 45→/// Format seconds into human-readable "XmYYs" or "Xs".
 46→fn format_duration(secs: u64) -> String {
 47→    if secs >= 60 {
 48→        format!("{}m{:02}s", secs / 60, secs % 60)
 49→    } else {
 50→        format!("{}s", secs)
 51→    }
 52→}
