     1→/// Auto-Claude implementation plan loader.
     2→///
     3→/// Parses `implementation_plan.json` files produced by the Auto-Claude
     4→/// orchestrator and exposes plan/phase/subtask data for CLI and Quick Look
     5→/// rendering.
     6→use anyhow::Context;
     7→use serde::Deserialize;
     8→use std::path::Path;
     9→
    10→// ── Data model ──────────────────────────────────────────────────────────
    11→
    12→/// Top-level Auto-Claude implementation plan.
    13→#[derive(Debug, Deserialize)]
    14→pub struct AcPlan {
    15→    pub phases: Vec<AcPhase>,
    16→}
    17→
    18→/// A phase within an implementation plan.
    19→#[derive(Debug, Deserialize)]
    20→pub struct AcPhase {
    21→    pub id: String,
    22→    pub name: String,
    23→    #[serde(default)]
    24→    pub subtasks: Vec<AcSubtask>,
    25→}
    26→
    27→/// A single subtask inside a phase.
    28→#[derive(Debug, Deserialize)]
    29→pub struct AcSubtask {
    30→    pub id: String,
    31→    pub description: String,
    32→    /// `"pending"` | `"in_progress"` | `"completed"`
    33→    #[serde(default = "default_status")]
    34→    pub status: String,
    35→}
    36→
    37→fn default_status() -> String {
    38→    "pending".to_string()
    39→}
    40→
    41→// ── Parsing ─────────────────────────────────────────────────────────────
    42→
    43→/// Parse an `implementation_plan.json` file into an [`AcPlan`].
    44→pub fn parse_plan(path: &Path) -> anyhow::Result<AcPlan> {
    45→    let data = std::fs::read_to_string(path)
    46→        .with_context(|| format!("failed to read plan: {}", path.display()))?;
    47→    let plan: AcPlan = serde_json::from_str(&data)
    48→        .with_context(|| format!("failed to parse plan JSON: {}", path.display()))?;
    49→    Ok(plan)
    50→}
    51→
    52→// ── Glyphs ──────────────────────────────────────────────────────────────
    53→
    54→/// Half-circle glyph encoding phase completion fraction.
    55→///
    56→/// Thresholds (from spec):
    57→/// - `0.0`        → `○` (U+25CB)
    58→/// - `0.01–0.33`  → `◔` (U+25D4)
    59→/// - `0.34–0.66`  → `◑` (U+25D1)
    60→/// - `0.67–0.99`  → `◕` (U+25D5)
    61→/// - `1.0`        → `●` (U+25CF)
    62→pub fn half_circle_glyph(frac: f64) -> char {
    63→    if frac <= 0.0 {
    64→        '○'
    65→    } else if frac <= 0.33 {
    66→        '◔'
    67→    } else if frac <= 0.66 {
    68→        '◑'
    69→    } else if frac < 1.0 {
    70→        '◕'
    71→    } else {
    72→        '●'
    73→    }
    74→}
