     1→/// Auto-Claude implementation plan loader.
     2→///
     3→/// Parses `implementation_plan.json` files produced by the Auto-Claude
     4→/// orchestrator and exposes plan/phase/subtask data for CLI and Quick Look
     5→/// rendering.
     6→use anyhow::Context;
     7→use serde::Deserialize;
     8→use std::path::{Path, PathBuf};
     9→
    10→// ── Data model ──────────────────────────────────────────────────────────
    11→
    12→/// Top-level Auto-Claude implementation plan.
    13→#[derive(Debug, Deserialize)]
    14→pub struct AcPlan {
    15→    pub phases: Vec<AcPhase>,
    16→}
    17→
    18→/// A phase within an implementation plan.
    19→#[derive(Debug, Deserialize)]
    20→pub struct AcPhase {
    21→    pub id: String,
    22→    pub name: String,
    23→    #[serde(default)]
    24→    pub subtasks: Vec<AcSubtask>,
    25→}
    26→
    27→/// A single subtask inside a phase.
    28→#[derive(Debug, Deserialize)]
    29→pub struct AcSubtask {
    30→    pub id: String,
    31→    pub description: String,
    32→    /// `"pending"` | `"in_progress"` | `"completed"`
    33→    #[serde(default = "default_status")]
    34→    pub status: String,
    35→}
    36→
    37→fn default_status() -> String {
    38→    "pending".to_string()
    39→}
    40→
    41→// ── Parsing ─────────────────────────────────────────────────────────────
    42→
    43→/// Parse an `implementation_plan.json` file into an [`AcPlan`].
    44→pub fn parse_plan(path: &Path) -> anyhow::Result<AcPlan> {
    45→    let data = std::fs::read_to_string(path)
    46→        .with_context(|| format!("failed to read plan: {}", path.display()))?;
    47→    let plan: AcPlan = serde_json::from_str(&data)
    48→        .with_context(|| format!("failed to parse plan JSON: {}", path.display()))?;
    49→    Ok(plan)
    50→}
    51→
    52→// ── Path resolution ─────────────────────────────────────────────────────
    53→
    54→/// Maximum number of parent directories to walk when searching for the
    55→/// project root.  Six levels is sufficient for typical mono-repo layouts
    56→/// (e.g. `repo/.cards/running/card.bop/` is 3 levels deep).
    57→const MAX_ANCESTOR_DEPTH: usize = 6;
    58→
    59→/// Walk parent directories from `start_dir` looking for a `.git` directory
    60→/// or a `.auto-claude` directory.  Returns the first ancestor that contains
    61→/// either marker, or `None` if none is found within [`MAX_ANCESTOR_DEPTH`]
    62→/// levels.
    63→///
    64→/// This is a pure filesystem check — no `git` subprocess required — so it
    65→/// works in minimal environments and in test temp-dirs that contain an
    66→/// `.auto-claude` directory without a full git repo.
    67→pub fn find_git_root(start_dir: &Path) -> Option<PathBuf> {
    68→    let canonical = start_dir.canonicalize().ok()?;
    69→    let mut current = canonical.as_path();
    70→
    71→    for _ in 0..MAX_ANCESTOR_DEPTH {
    72→        if current.join(".git").exists() || current.join(".auto-claude").exists() {
    73→            return Some(current.to_path_buf());
    74→        }
    75→        current = current.parent()?;
    76→    }
    77→    None
    78→}
    79→
    80→/// Resolve the `implementation_plan.json` path for a given Auto-Claude spec
    81→/// ID.
    82→///
    83→/// Looks for `<git_root>/.auto-claude/specs/<ac_spec_id>-*/implementation_plan.json`.
    84→/// Returns the first match (there should only be one per ID prefix), or
    85→/// `None` if no matching directory exists.
    86→pub fn resolve_spec_dir(git_root: &Path, ac_spec_id: &str) -> Option<PathBuf> {
    87→    let specs_dir = git_root.join(".auto-claude").join("specs");
    88→    let prefix = format!("{}-", ac_spec_id);
    89→
    90→    let entries = std::fs::read_dir(&specs_dir).ok()?;
    91→    for entry in entries.flatten() {
    92→        let name = entry.file_name();
    93→        let Some(name_str) = name.to_str() else {
    94→            continue;
    95→        };
    96→        if name_str.starts_with(&prefix) && entry.path().is_dir() {
    97→            let plan_path = entry.path().join("implementation_plan.json");
    98→            if plan_path.exists() {
    99→                return Some(plan_path);
   100→            }
   101→        }
   102→    }
   103→    None
   104→}
   105→
   106→// ── Glyphs ──────────────────────────────────────────────────────────────
   107→
   108→/// Half-circle glyph encoding phase completion fraction.
   109→///
   110→/// Thresholds (from spec):
   111→/// - `0.0`        → `○` (U+25CB)
   112→/// - `0.01–0.33`  → `◔` (U+25D4)
   113→/// - `0.34–0.66`  → `◑` (U+25D1)
   114→/// - `0.67–0.99`  → `◕` (U+25D5)
   115→/// - `1.0`        → `●` (U+25CF)
   116→pub fn half_circle_glyph(frac: f64) -> char {
   117→    if frac <= 0.0 {
   118→        '○'
   119→    } else if frac <= 0.33 {
   120→        '◔'
   121→    } else if frac <= 0.66 {
   122→        '◑'
   123→    } else if frac < 1.0 {
   124→        '◕'
   125→    } else {
   126→        '●'
   127→    }
   128→}
