     2→///
     3→/// Parses `implementation_plan.json` files produced by the Auto-Claude
     4→/// orchestrator and exposes plan/phase/subtask data for CLI and Quick Look
     5→/// rendering.
     6→use anyhow::Context;
     7→use bop_core::Meta;
     8→use serde::Deserialize;
     9→use std::path::{Path, PathBuf};
    10→
    11→use crate::render::CardView;
    12→
    13→// ── Data model ──────────────────────────────────────────────────────────
    14→
    15→/// Top-level Auto-Claude implementation plan.
    16→#[derive(Debug, Deserialize)]
    17→pub struct AcPlan {
    18→    pub phases: Vec<AcPhase>,
    19→}
    20→
    21→/// A phase within an implementation plan.
    22→#[derive(Debug, Deserialize)]
    23→pub struct AcPhase {
    24→    pub id: String,
    25→    pub name: String,
    26→    #[serde(default)]
    27→    pub subtasks: Vec<AcSubtask>,
    28→}
    29→
    30→/// A single subtask inside a phase.
    31→#[derive(Debug, Deserialize)]
    32→pub struct AcSubtask {
    33→    pub id: String,
    34→    pub description: String,
    35→    /// `"pending"` | `"in_progress"` | `"completed"`
    36→    #[serde(default = "default_status")]
    37→    pub status: String,
    38→}
    39→
    40→fn default_status() -> String {
    41→    "pending".to_string()
    42→}
    43→
    44→// ── Parsing ─────────────────────────────────────────────────────────────
    45→
    46→/// Parse an `implementation_plan.json` file into an [`AcPlan`].
    47→pub fn parse_plan(path: &Path) -> anyhow::Result<AcPlan> {
    48→    let data = std::fs::read_to_string(path)
    49→        .with_context(|| format!("failed to read plan: {}", path.display()))?;
    50→    let plan: AcPlan = serde_json::from_str(&data)
    51→        .with_context(|| format!("failed to parse plan JSON: {}", path.display()))?;
    52→    Ok(plan)
    53→}
    54→
    55→// ── Path resolution ─────────────────────────────────────────────────────
    56→
    57→/// Maximum number of parent directories to walk when searching for the
    58→/// project root.  Six levels is sufficient for typical mono-repo layouts
    59→/// (e.g. `repo/.cards/running/card.bop/` is 3 levels deep).
    60→const MAX_ANCESTOR_DEPTH: usize = 6;
    61→
    62→/// Walk parent directories from `start_dir` looking for a `.git` directory
    63→/// or a `.auto-claude` directory.  Returns the first ancestor that contains
    64→/// either marker, or `None` if none is found within [`MAX_ANCESTOR_DEPTH`]
    65→/// levels.
    66→///
    67→/// This is a pure filesystem check — no `git` subprocess required — so it
    68→/// works in minimal environments and in test temp-dirs that contain an
    69→/// `.auto-claude` directory without a full git repo.
    70→pub fn find_git_root(start_dir: &Path) -> Option<PathBuf> {
    71→    let canonical = start_dir.canonicalize().ok()?;
    72→    let mut current = canonical.as_path();
    73→
    74→    for _ in 0..MAX_ANCESTOR_DEPTH {
    75→        if current.join(".git").exists() || current.join(".auto-claude").exists() {
    76→            return Some(current.to_path_buf());
    77→        }
    78→        current = current.parent()?;
    79→    }
    80→    None
    81→}
    82→
    83→/// Resolve the `implementation_plan.json` path for a given Auto-Claude spec
    84→/// ID.
    85→///
    86→/// Looks for `<git_root>/.auto-claude/specs/<ac_spec_id>-*/implementation_plan.json`.
    87→/// Returns the first match (there should only be one per ID prefix), or
    88→/// `None` if no matching directory exists.
    89→pub fn resolve_spec_dir(git_root: &Path, ac_spec_id: &str) -> Option<PathBuf> {
    90→    let specs_dir = git_root.join(".auto-claude").join("specs");
    91→    let prefix = format!("{}-", ac_spec_id);
    92→
    93→    let entries = std::fs::read_dir(&specs_dir).ok()?;
    94→    for entry in entries.flatten() {
    95→        let name = entry.file_name();
    96→        let Some(name_str) = name.to_str() else {
    97→            continue;
    98→        };
    99→        if name_str.starts_with(&prefix) && entry.path().is_dir() {
   100→            let plan_path = entry.path().join("implementation_plan.json");
   101→            if plan_path.exists() {
   102→                return Some(plan_path);
   103→            }
   104→        }
   105→    }
   106→    None
   107→}
   108→
   109→// ── Glyphs ──────────────────────────────────────────────────────────────
   110→
   111→/// Half-circle glyph encoding phase completion fraction.
   112→///
   113→/// Thresholds (from spec):
   114→/// - `0.0`        → `○` (U+25CB)
   115→/// - `0.01–0.33`  → `◔` (U+25D4)
   116→/// - `0.34–0.66`  → `◑` (U+25D1)
   117→/// - `0.67–0.99`  → `◕` (U+25D5)
   118→/// - `1.0`        → `●` (U+25CF)
   119→pub fn half_circle_glyph(frac: f64) -> char {
   120→    if frac <= 0.0 {
   121→        '○'
   122→    } else if frac <= 0.33 {
   123→        '◔'
   124→    } else if frac <= 0.66 {
   125→        '◑'
   126→    } else if frac < 1.0 {
   127→        '◕'
   128→    } else {
   129→        '●'
   130→    }
   131→}
   132→
   133→// ── Plan summary ────────────────────────────────────────────────────────
   134→
   135→/// Aggregate statistics from an [`AcPlan`].
   136→#[derive(Debug, Clone)]
   137→pub struct PlanSummary {
   138→    /// Number of completed subtasks across all phases.
   139→    pub completed: usize,
   140→    /// Total number of subtasks across all phases.
   141→    pub total: usize,
   142→    /// Name of the current phase (first phase with incomplete subtasks),
   143→    /// or the last phase name if everything is done.
   144→    pub current_phase_name: Option<String>,
   145→    /// Fraction of subtasks completed in the current phase (0.0–1.0).
   146→    pub current_phase_frac: f64,
   147→}
   148→
   149→/// Summarise an [`AcPlan`] into completion counts and current-phase info.
   150→///
   151→/// The "current phase" is the first phase that still has at least one
   152→/// non-completed subtask.  If every subtask in every phase is completed
   153→/// the last phase is returned with `current_phase_frac = 1.0`.
   154→///
   155→/// An empty plan (no phases) returns zeros and `None` for the phase name.
   156→pub fn plan_summary(plan: &AcPlan) -> PlanSummary {
   157→    let mut completed: usize = 0;
   158→    let mut total: usize = 0;
   159→    let mut current_phase_name: Option<String> = None;
   160→    let mut current_phase_frac: f64 = 0.0;
   161→
   162→    for phase in &plan.phases {
   163→        let phase_total = phase.subtasks.len();
   164→        let phase_done = phase
   165→            .subtasks
   166→            .iter()
   167→            .filter(|s| s.status == "completed")
   168→            .count();
   169→
   170→        total += phase_total;
   171→        completed += phase_done;
   172→
   173→        // Current phase = first phase with incomplete subtasks.
   174→        if current_phase_name.is_none() && phase_done < phase_total {
   175→            current_phase_name = Some(phase.name.clone());
   176→            current_phase_frac = if phase_total > 0 {
   177→                phase_done as f64 / phase_total as f64
   178→            } else {
   179→                0.0
   180→            };
   181→        }
   182→    }
   183→
   184→    // If all phases are complete, report the last phase at 100 %.
   185→    if current_phase_name.is_none() {
   186→        if let Some(last) = plan.phases.last() {
   187→            current_phase_name = Some(last.name.clone());
   188→            current_phase_frac = 1.0;
   189→        }
   190→    }
   191→
   192→    PlanSummary {
   193→        completed,
   194→        total,
   195→        current_phase_name,
   196→        current_phase_frac,
   197→    }
   198→}
   199→
   200→// ── CardView enrichment ─────────────────────────────────────────────────
   201→
   202→/// Enrich a [`CardView`] with Auto-Claude plan data.
   203→///
   204→/// If `meta.ac_spec_id` is set and the corresponding
   205→/// `implementation_plan.json` can be found under `git_root`, this function
   206→/// populates `phase_name`, `phase_frac`, and `progress` on the view.
   207→///
   208→/// Silently returns without changes when:
   209→/// - `ac_spec_id` is `None`
   210→/// - the spec directory cannot be resolved
   211→/// - the plan file cannot be parsed
   212→pub fn enrich_card_view(view: &mut CardView, meta: &Meta, git_root: &Path) {
   213→    let ac_spec_id = match &meta.ac_spec_id {
   214→        Some(id) => id,
   215→        None => return,
   216→    };
   217→
   218→    let plan_path = match resolve_spec_dir(git_root, ac_spec_id) {
   219→        Some(p) => p,
   220→        None => return,
   221→    };
   222→
   223→    let plan = match parse_plan(&plan_path) {
   224→        Ok(p) => p,
   225→        Err(_) => return,
   226→    };
   227→
   228→    let summary = plan_summary(&plan);
   229→
   230→    view.phase_name = summary.current_phase_name;
   231→    view.phase_frac = summary.current_phase_frac as f32;
   232→
   233→    if summary.total > 0 {
   234→        view.progress = ((summary.completed as f64 / summary.total as f64) * 100.0) as u8;
   235→    }
   236→}
