    96→/// to defaults — the caller may enrich them from AC plan data afterward.
    97→pub fn from_meta(meta: &Meta, state: &str) -> CardView {
    98→    let last_run = meta.runs.last();
    99→
   100→    CardView {
   101→        id: meta.id.clone(),
   102→        state: state.to_string(),
   103→        glyph: meta.glyph.clone(),
   104→        token: meta.token.clone(),
   105→        title: meta.title.clone().unwrap_or_else(|| meta.id.clone()),
   106→        stage: meta.stage.clone(),
   107→        priority: meta.priority,
   108→        progress: meta.progress.unwrap_or(0),
   109→        provider: last_run
   110→            .map(|r| r.provider.clone())
   111→            .filter(|s| !s.is_empty()),
   112→        elapsed_s: last_run.and_then(|r| r.duration_s),
   113→        phase_name: None,
   114→        phase_frac: 0.0,
   115→        failure_reason: meta.failure_reason.clone(),
