   162→/// Pick the concrete renderer for the detected terminal level.
   163→fn select_renderer(caps: &TermCaps) -> Box<dyn CardRenderer> {
   164→    match caps.level {
   165→        TermLevel::Dumb => Box::new(dumb::DumbRenderer),
   166→        TermLevel::Basic => Box::new(basic::BasicRenderer),
   167→        TermLevel::Extended => Box::new(extended::ExtendedRenderer { width: caps.width }),
   168→        TermLevel::Full => Box::new(full::FullRenderer { width: caps.width }),
   169→        TermLevel::TrueColor => Box::new(truecolor::TrueColorRenderer {
   170→            width: caps.width,
   171→            two_column: caps.two_column,
   172→        }),
   173→    }
   174→}
