   150→///
   151→/// The "current phase" is the first phase that still has at least one
   152→/// non-completed subtask.  If every subtask in every phase is completed
   153→/// the last phase is returned with `current_phase_frac = 1.0`.
   154→///
   155→/// An empty plan (no phases) returns zeros and `None` for the phase name.
   156→pub fn plan_summary(plan: &AcPlan) -> PlanSummary {
   157→    let mut completed: usize = 0;
   158→    let mut total: usize = 0;
   159→    let mut current_phase_name: Option<String> = None;
   160→    let mut current_phase_frac: f64 = 0.0;
   161→
   162→    for phase in &plan.phases {
   163→        let phase_total = phase.subtasks.len();
   164→        let phase_done = phase
   165→            .subtasks
   166→            .iter()
   167→            .filter(|s| s.status == "completed")
   168→            .count();
   169→
   170→        total += phase_total;
   171→        completed += phase_done;
   172→
   173→        // Current phase = first phase with incomplete subtasks.
   174→        if current_phase_name.is_none() && phase_done < phase_total {
   175→            current_phase_name = Some(phase.name.clone());
   176→            current_phase_frac = if phase_total > 0 {
   177→                phase_done as f64 / phase_total as f64
   178→            } else {
   179→                0.0
   180→            };
   181→        }
   182→    }
   183→
   184→    // If all phases are complete, report the last phase at 100 %.
   185→    if current_phase_name.is_none() {
   186→        if let Some(last) = plan.phases.last() {
   187→            current_phase_name = Some(last.name.clone());
   188→            current_phase_frac = 1.0;
   189→        }
   190→    }
   191→
   192→    PlanSummary {
   193→        completed,
   194→        total,
   195→        current_phase_name,
   196→        current_phase_frac,
   197→    }
   198→}
