   122→// ── Board dispatch ──────────────────────────────────────────────────────────
   123→
   124→/// Render a full board to a `String`, selecting the renderer by [`TermLevel`].
   125→///
   126→/// `views` is a list of `(section_label, cards)` pairs — one per state group.
   127→/// Width is re-queried from `caps` on every call (never cached).
   128→pub fn render_board(caps: &TermCaps, views: &[(String, Vec<CardView>)], stats: &Stats) -> String {
   129→    let renderer: Box<dyn CardRenderer> = select_renderer(caps);
   130→    let mut out = String::new();
   131→
   132→    for (i, (label, cards)) in views.iter().enumerate() {
   133→        out.push_str(&renderer.render_section_header(label, cards.len()));
   134→        out.push('\n');
   135→
   136→        for card in cards {
   137→            out.push_str(&renderer.render_card_row(card));
   138→            out.push('\n');
   139→
   140→            if card.progress > 0 || card.phase_name.is_some() {
   141→                out.push_str(&renderer.render_progress(
   142→                    card.progress,
   143→                    card.phase_name.as_deref(),
   144→                    card.phase_frac,
   145→                ));
   146→                out.push('\n');
   147→            }
   148→        }
   149→
   150→        // Blank line between sections (but not after the last).
   151→        if i < views.len() - 1 {
   152→            out.push('\n');
   153→        }
   154→    }
   155→
   156→    out.push_str(&renderer.render_footer(stats));
   157→    out.push('\n');
   158→
   159→    out
   160→}
   161→
   162→/// Pick the concrete renderer for the detected terminal level.
   163→fn select_renderer(caps: &TermCaps) -> Box<dyn CardRenderer> {
   164→    match caps.level {
   165→        TermLevel::Dumb => Box::new(dumb::DumbRenderer),
   166→        TermLevel::Basic => Box::new(basic::BasicRenderer),
   167→        TermLevel::Extended => Box::new(extended::ExtendedRenderer { width: caps.width }),
   168→        TermLevel::Full => Box::new(full::FullRenderer { width: caps.width }),
   169→        TermLevel::TrueColor => Box::new(truecolor::TrueColorRenderer {
   170→            width: caps.width,
   171→            two_column: caps.two_column,
   172→        }),
   173→    }
   174→}
