    34→/// Calculate statistics: count cards by state and compute average duration.
    35→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
    36→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
    37→    let mut by_state = HashMap::new();
    38→    let mut total = 0;
    39→    let mut durations = Vec::new();
    40→
    41→    for state in &states {
    42→        // Process root-level state directory
    43→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
    44→
    45→        // Process team-* directories
    46→        if let Ok(entries) = fs::read_dir(root) {
    47→            for entry in entries.flatten() {
    48→                let team_path = entry.path();
    49→                if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
    50→                    collect_state_stats(
    51→                        &team_path,
    52→                        state,
    53→                        &mut by_state,
    54→                        &mut total,
    55→                        &mut durations,
    56→                    )?;
    57→                }
    58→            }
    59→        }
    60→    }
    61→
    62→    let avg_duration_s = if durations.is_empty() {
    63→        None
    64→    } else {
    65→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
    66→    };
    67→
    68→    let success_rate_pct = {
    69→        let done = by_state.get("done").copied().unwrap_or(0);
    70→        let failed = by_state.get("failed").copied().unwrap_or(0);
    71→        if done + failed > 0 {
    72→            Some((done as f64 / (done + failed) as f64) * 100.0)
    73→        } else {
    74→            None
    75→        }
    76→    };
    77→
    78→    Ok(CardStats {
    79→        total,
    80→        by_state,
    81→        avg_duration_s,
    82→        success_rate_pct,
    83→    })
    84→}
