   126→/// Collect all cards for the given state filter into `(label, Vec<CardView>)` groups.
   127→fn collect_card_groups(
   128→    root: &Path,
   129→    state_filter: &str,
   130→) -> anyhow::Result<Vec<(String, Vec<render::CardView>)>> {
   131→    let states = resolve_states(state_filter);
   132→    let git_root = acplan::find_git_root(root);
   133→    let mut groups = Vec::new();
   134→
   135→    for state in &states {
   136→        // Collect root-level cards
   137→        let root_cards = collect_card_views(root, state, git_root.as_deref())?;
   138→        if !root_cards.is_empty() {
   139→            groups.push((state.to_string(), root_cards));
   140→        }
   141→
   142→        // Collect team-* directory cards
   143→        if let Ok(entries) = fs::read_dir(root) {
   144→            let mut team_dirs: Vec<_> = entries
   145→                .flatten()
   146→                .filter(|e| {
   147→                    let name = e.file_name();
   148→                    let s = name.to_string_lossy();
   149→                    e.path().is_dir() && s.starts_with("team-")
   150→                })
   151→                .collect();
   152→            team_dirs.sort_by_key(|e| e.file_name());
   153→            for entry in team_dirs {
   154→                let team_name = entry.file_name().to_string_lossy().into_owned();
   155→                let team_cards = collect_card_views(&entry.path(), state, git_root.as_deref())?;
   156→                if !team_cards.is_empty() {
   157→                    groups.push((format!("{}/{}", team_name, state), team_cards));
   158→                }
   159→            }
   160→        }
   161→    }
   162→
   163→    Ok(groups)
   164→}
