     1→/// Auto-Claude implementation plan loader.
     2→///
     3→/// Parses `implementation_plan.json` files produced by the Auto-Claude
     4→/// orchestrator and exposes plan/phase/subtask data for CLI and Quick Look
     5→/// rendering.
     6→use anyhow::Context;
     7→use bop_core::Meta;
     8→use serde::Deserialize;
     9→use std::path::{Path, PathBuf};
    10→
    11→use crate::render::CardView;
    12→
    13→// ── Data model ──────────────────────────────────────────────────────────
    14→
    15→/// Top-level Auto-Claude implementation plan.
    16→#[derive(Debug, Deserialize)]
    17→pub struct AcPlan {
    18→    pub phases: Vec<AcPhase>,
    19→}
    20→
    21→/// A phase within an implementation plan.
    22→#[derive(Debug, Deserialize)]
    23→pub struct AcPhase {
    24→    pub id: String,
    25→    pub name: String,
    26→    #[serde(default)]
    27→    pub subtasks: Vec<AcSubtask>,
    28→}
    29→
    30→/// A single subtask inside a phase.
    31→#[derive(Debug, Deserialize)]
    32→pub struct AcSubtask {
    33→    pub id: String,
    34→    pub description: String,
    35→    /// `"pending"` | `"in_progress"` | `"completed"`
    36→    #[serde(default = "default_status")]
    37→    pub status: String,
    38→}
    39→
    40→fn default_status() -> String {
    41→    "pending".to_string()
    42→}
    43→
    44→// ── Parsing ─────────────────────────────────────────────────────────────
    45→
    46→/// Parse an `implementation_plan.json` file into an [`AcPlan`].
    47→pub fn parse_plan(path: &Path) -> anyhow::Result<AcPlan> {
    48→    let data = std::fs::read_to_string(path)
    49→        .with_context(|| format!("failed to read plan: {}", path.display()))?;
    50→    let plan: AcPlan = serde_json::from_str(&data)
    51→        .with_context(|| format!("failed to parse plan JSON: {}", path.display()))?;
    52→    Ok(plan)
    53→}
    54→
    55→// ── Path resolution ─────────────────────────────────────────────────────
    56→
    57→/// Maximum number of parent directories to walk when searching for the
    58→/// project root.  Six levels is sufficient for typical mono-repo layouts
    59→/// (e.g. `repo/.cards/running/card.bop/` is 3 levels deep).
    60→const MAX_ANCESTOR_DEPTH: usize = 6;
    61→
    62→/// Walk parent directories from `start_dir` looking for a `.git` directory
    63→/// or a `.auto-claude` directory.  Returns the first ancestor that contains
    64→/// either marker, or `None` if none is found within [`MAX_ANCESTOR_DEPTH`]
    65→/// levels.
    66→///
    67→/// This is a pure filesystem check — no `git` subprocess required — so it
    68→/// works in minimal environments and in test temp-dirs that contain an
    69→/// `.auto-claude` directory without a full git repo.
    70→pub fn find_git_root(start_dir: &Path) -> Option<PathBuf> {
    71→    let canonical = start_dir.canonicalize().ok()?;
    72→    let mut current = canonical.as_path();
    73→
    74→    for _ in 0..MAX_ANCESTOR_DEPTH {
    75→        if current.join(".git").exists() || current.join(".auto-claude").exists() {
    76→            return Some(current.to_path_buf());
    77→        }
    78→        current = current.parent()?;
    79→    }
    80→    None
    81→}
    82→
    83→/// Resolve the `implementation_plan.json` path for a given Auto-Claude spec
    84→/// ID.
    85→///
    86→/// Looks for `<git_root>/.auto-claude/specs/<ac_spec_id>-*/implementation_plan.json`.
    87→/// Returns the first match (there should only be one per ID prefix), or
    88→/// `None` if no matching directory exists.
    89→pub fn resolve_spec_dir(git_root: &Path, ac_spec_id: &str) -> Option<PathBuf> {
    90→    let specs_dir = git_root.join(".auto-claude").join("specs");
    91→    let prefix = format!("{}-", ac_spec_id);
    92→
    93→    let entries = std::fs::read_dir(&specs_dir).ok()?;
    94→    for entry in entries.flatten() {
    95→        let name = entry.file_name();
    96→        let Some(name_str) = name.to_str() else {
    97→            continue;
    98→        };
    99→        if name_str.starts_with(&prefix) && entry.path().is_dir() {
   100→            let plan_path = entry.path().join("implementation_plan.json");
   101→            if plan_path.exists() {
   102→                return Some(plan_path);
   103→            }
   104→        }
   105→    }
   106→    None
   107→}
